package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
)

func handleRequest(w http.ResponseWriter, r *http.Request) {
	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Failed to read request body", http.StatusInternalServerError)
		return
	}

	// Close the request body
	err = r.Body.Close()
	if err != nil {
		http.Error(w, "Failed to close request body", http.StatusInternalServerError)
		return
	}

	// Print the request content
	fmt.Println("Request Content:")
	fmt.Println(string(body))

	// Send a response back to the client
	w.Write([]byte("Request content received and printed."))
}

func main() {
	// Set up the HTTP server
	http.HandleFunc("/", handleRequest)

	// Start the HTTP server on port 8080
	http.ListenAndServe(":8080", nil)
}
```

### Explanation:
1. **Reading the Request Body**:
    - `ioutil.ReadAll(r.Body)` reads the entire request body into a byte slice.
